import{bQ as s,aZ as n,aL as o,u as t,v as r,I as g,bJ as a,H as e,G as i}from"./chunks/framework.D-yUR65U.js";const p=JSON.parse('{"title":"积土成山，风雨兴焉；积水成渊，蛟龙生焉。","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://coderama.top/pages/message"}]]},"headers":[],"relativePath":"pages/message.md","filePath":"pages/message.md","lastUpdated":1776074768000}'),l={id:"积土成山-风雨兴焉-积水成渊-蛟龙生焉。",tabindex:"-1"};const c=s({name:"pages/message.md"},[["render",function(s,p,c,m,d,_){const u=n("font");return o(),t("div",null,[r("h1",l,[g(u,{color:"#006341"},{default:a(()=>[...p[0]||(p[0]=[e("积土成山，风雨兴焉；积水成渊，蛟龙生焉。",-1)])]),_:1}),p[1]||(p[1]=e()),p[2]||(p[2]=r("a",{class:"header-anchor",href:"#积土成山-风雨兴焉-积水成渊-蛟龙生焉。","aria-label":'Permalink to "<font color=#006341>积土成山，风雨兴焉；积水成渊，蛟龙生焉。</font>"'},"​",-1))]),p[3]||(p[3]=i('<blockquote><p>AI的强大只是基于其背后庞大的语料库以及足以应对各种情况的训练集；其核心是从数据中学习规律，并用于判断或预测（类Bayes推断）。<br> AI说一千道一万，其实离不开“数据”。如果把它的“图书馆”搬走，那么它就什么都不是了，无论是在训练阶段的随机猜测、过拟合，还是推理阶段的分布偏移，都会将效率腰斩。</p></blockquote><p>人们经常这样评价AI，并强调“独立思考，不依赖AI”的重要性。但是他们万万没想到，人类的大脑与AI又何其相似？只不过一个解构的，高效的，不挑环境的“数字人”，就触及了自己的某些利益？我们细究：</p><p>林纳斯开发的Linux操作系统可谓人类历史中的一颗明珠，让我们来彻底看看它的发展历程，但在此之前，我们先看一下编程语言的老大——C语言的发展历程：</p><p><strong>1957</strong>年5月，美国一些主要的<strong>计算机用户</strong>组向ACM<strong>提议</strong>开发一种与计算机（大型机）无关的科学用程序设计语言；同年12月，<strong>ALGOL58</strong>报告发表，被视程序设计语言思想的集成者。<strong>1963</strong>年，剑桥大学又在ALGOL60的基础上开发了<strong>CPL</strong>组合编程语言；随后，在<strong>1966</strong>年，剑桥大学的马丁·理察德以CPL语言为基础，通过简化，发明了<strong>BCPL</strong>语言；之后：<strong>1966</strong>，基于BCPL简化出<strong>B语言</strong>；<strong>1972</strong>，基于B设计出<strong>C语言</strong>。可以看到现在被众星拱月的C语言，也不是从石头缝里蹦出来的，它也是基于简单的代码，经历一次次迭代、扩展和简化才得以获得今日的辉煌。</p><p>好了，现在言归正传，回到Linux的开发动机：</p><p><strong>1964</strong>年，贝尔实验室、麻省理工学院及美国通用电气公司共同参与研发了分时操作系统<strong>Multics</strong>；尔后贝尔实验室又将其简化，于<strong>20世纪60年代</strong>推出了<strong>Unix</strong>操作系统，但后期因为商业化导致src获得受限，催生了自由软件运动；<strong>1983</strong>年，<strong>GNU</strong>计划发起，旨在创建完全自由的类Unix操作系统，一并推出GPL许可证，奠基自由软件发展；林纳斯在1991年对Minix操作系统不满，希望开发一个更强大、适合386处理器的类Unix系统。</p><p>林纳斯最初为了获得学校Unix服务器的数据，利用GNU的工具链在Minix下开发程序。1991年8月25日，其在comp.os.minix下发帖宣布开发自由操作系统；<strong>1991</strong>年9月17日，<strong>Linux 0.01</strong>发布：约10239行代码，<strong>依赖</strong>Minix环境。</p><p>为了减少开发维护成本及贯彻“完全自由”的理念，林纳斯后来将Linux内核接入GNU General Public License协议，迅速吸引全球开发者参与；<strong>1992</strong>年成立<strong>Finux用户组</strong>；同年，<strong>Slackware发行版</strong>发布；<strong>1993</strong>年<strong>Debian</strong>项目启动。<strong>2005</strong>年，林纳斯创建<strong>Git</strong>以支持Linux内核开发。</p><p>懂理的客官会发现，这些智慧结晶还真就不是一个人殚精竭虑凝结而成，而是数十年间，不同人的工作经验集结而成。哪怕再举一个极端的例子也不为过——那个开发了TempleOS，用代码与上帝对话的奇才程序员Terry Davis——</p><blockquote><p>耶稣说 “我三日內要再建立起来（一个神殿）”，而我可以三天写出一个编译器。<br> 阿三黑鬼白痴博士。<br> 1999年我开车撞死了一个黑鬼警察……<br> 我他妈的写了个编译器。Linus 也没写出编译器来，还要被 Stallman 奚落。</p></blockquote><p><strong>TempleOS</strong>是操作系统历史中唯一的“<strong>一人之功</strong>”。Terry为了完成上帝的旨意，自己从头开始用<strong>C语言</strong>构建了一个非优化编译器，遍历AST，编译为x86_64 ASM尔后输入gcc。包括后期所需的集成开发系统、文件系统、内核均是独立完成……强如此辈都没有选择从ALGOL和Unix开始重新编写工具链，而是从很完善的C语言体系着手，最终为上帝建了一座恢宏的，运行在64位Ring0上的赛博神殿，由此可知站在巨人肩膀上的重要性！如果事事都求从0开始，就连钻木取火都要从种树，砍木头学起，人类社会的发展将是一次又一次地洗牌……</p><p>说了这么多，笔者想表达的还是<strong>智慧的局限性</strong>：古往今来多少文化瑰宝，哪怕穷尽一生从头推演，也未必能得到同等结果，既然前人已努力过，为何不大胆使用？对于AI也是一样，既然已经存在成熟的经验，为何不能高效利用实例来强化推演效率，而是一味苛责其依赖人类语料，无自我思维？说这些话的个体，又拥有多少独立解决问题的能力？若是让他们不依赖别人方法，孤独地解决一个难题，想必定是一副搔首弄姿之态！</p><p>但是AI的急速发展也带来一个致命短板：人类工作需要卡路里，需要美好心情，需要心无旁骛，需要合理报酬……而服务器呢？只需要电力和算力就可以。无论最终的效率如何，AI可胜出太多了。霍金在生前就警告过人类，“人工智能的全面发展可能会给人类带来<strong>终结</strong>”，现在看来，救赎之道似乎就在人类心中，但是能否祓除五毒，损失一点利益，似乎没有人愿意去做，那么人类的毁灭也是顺理成章的了。</p><p>人类，自求多福吧！利用但不滥用人工智慧，脚踏实地慢慢努力，尽可能删除战争，竭尽所能抵制蜥蜴人的攻势，诚为当务之急！</p><p><a class="img-fancybox" href="https://upload.wikimedia.org/wikipedia/commons/5/5b/Michelangelo_-_Creation_of_Adam_%28cropped%29.jpg" data-fancybox="gallery" data-caption="向内而求，最后的机会"><img class="post-img" src="https://upload.wikimedia.org/wikipedia/commons/5/5b/Michelangelo_-_Creation_of_Adam_%28cropped%29.jpg" alt="向内而求，最后的机会" loading="lazy"><span class="post-img-tip">向内而求，最后的机会</span></a></p><p>其实这只是一个编程语言和操作系统的发展史小记:-)</p>',16))])}]]);export{p as __pageData,c as default};
